+
+const SPECTRAL_COLORS: Record<string, number> = {
+  O: 0x9bb0ff, B: 0xaabfff, A: 0xcad7ff, F: 0xf8f7ff,
+  G: 0xfff4ea, K: 0xffd2a1, M: 0xffb56c, L: 0xff8833,
+};
