+function warmColor(tempK: number): THREE.Color {
+  const t = Math.max(0, Math.min(1, (tempK - 100) / 400));
+  return new THREE.Color().setHSL(0.02 + t * 0.06, 0.9, 0.3 + t * 0.2);
