+    Molecule { name: "NH3",  wavelength_um: 3.0,  width_um: 0.12 },
+];
+
+#[derive(Debug, Clone)]
+#[allow(dead_code)]
+struct Spectrum {
+    target_id: u64,
+    target_name: String,
+    wavelengths: Vec<f64>,
+    flux: Vec<f64>,
+    detected_molecules: Vec<String>,
