+        // Blackbody-ish continuum (simplified)
+        let continuum = 1.0 / (1.0 + ((wl - 2.0) / 2.0).powi(2));
+        let noise = (lcg_f64(&mut rng) - 0.5) * 0.02;
+        flux.push(continuum + noise);
+    }
