+            let confidence = 0.5 + lcg_f64(&mut rng) * 0.5;
+            edges.push(CoOccurrenceEdge {
+                molecule_a: mols[i].clone(),
+                molecule_b: mols[j].clone(),
+                confidence,
+            });
+        }
+    }
+    edges
+}
