+// Equilibrium expectation: which molecule pairs would be expected together
+fn equilibrium_expectation(a: &str, b: &str) -> f64 {
+    match (a, b) {
+        ("CO2", "H2O") | ("H2O", "CO2") => 0.8,  // common together
+        ("O3", "CH4") | ("CH4", "O3") => 0.05,    // disequilibrium pair!
+        ("H2O", "O3") | ("O3", "H2O") => 0.3,
+        ("NH3", "CH4") | ("CH4", "NH3") => 0.4,
+        ("CO2", "CH4") | ("CH4", "CO2") => 0.2,
+        _ => 0.5,
+    }
+}
